    //

      // ── PROXY ────────────────────────────────────────────────────────────────
      //
      // basePath is computed from the current URL at runtime, so this file
      // works from any host with zero configuration changes:
      //
      //   Render   https://my-app.onrender.com/logo.svg  -> basePath = "/"
      //   jsDelivr https://cdn.jsdelivr.net/gh/u/r@v/logo.svg -> basePath = "/gh/u/r@v/"
      //
      // The scramjet prefix and SW scope are derived from basePath,
      // so proxy requests always fall within the SW scope.

      var basePath = location.pathname.replace(/[^\/]*$/, '');
      var SCRAM_PREFIX = basePath + 'scram/';
      var proxyReady = false;
      var scramController = null;

      function waitForRuntime(ms) {
        ms = ms || 10000;
        return new Promise(function(resolve, reject) {
          var t = Date.now();
          (function tick() {
            var ok = typeof $scramjetLoadController === 'function'
                  && typeof BareMux !== 'undefined'
                  && typeof BareMux.BareMuxConnection === 'function';
            if (ok) { return resolve(); }
            if (Date.now() - t > ms) { return reject(new Error('Proxy runtime scripts did not load in time')); }
            setTimeout(tick, 100);
          }());
        });
      }

      function toProxiedUrl(url) {
        if (!proxyReady || !scramController) { return url; }
        try { return scramController.encodeUrl(url); }
        catch (e) { return url; }
      }

      function initProxy() {
        var status = document.getElementById('proxy-status');
        status.classList.add('visible');

        waitForRuntime()
          .then(function() {
            return navigator.serviceWorker.register('./sw.js', { scope: basePath || '/' });
          })
          .then(function() {
            return navigator.serviceWorker.ready;
          })
          .then(function() {
            var conn = new BareMux.BareMuxConnection('./runtime/baremux/worker.js');
            var proto = location.protocol === 'https:' ? 'wss' : 'ws';
            var wisp = proto + '://' + location.host + '/ws/';
            return conn.setTransport('./runtime/libcurl/index.mjs', [{ wisp: wisp }]);
          })
          .then(function() {
            var SC = $scramjetLoadController();
            scramController = new SC.ScramjetController({
              prefix: SCRAM_PREFIX,
              files: {
                wasm: './runtime/scramjet/scramjet.wasm.wasm',
                all:  './runtime/scramjet/scramjet.all.js',
                sync: './runtime/scramjet/scramjet.sync.js'
              },
              flags: { sourcemaps: false }
            });
            return scramController.init();
          })
          .then(function() {
            proxyReady = true;
            status.textContent = 'Proxy ready';
            setTimeout(function() { status.classList.remove('visible'); }, 1800);
          })
          .catch(function(err) {
            console.error('Proxy init:', err);
            status.textContent = 'Proxy offline - direct connections only';
          });
      }

      // ── STATE ────────────────────────────────────────────────────────────────

      var normalTabs    = [];
      var incognitoTabs = [];
      var isIncognito   = false;
      var activeTabId   = null;
      var tabCounter    = 0;
      var bookmarks     = JSON.parse(localStorage.getItem('cineweb_bookmarks') || '[]');

      var defaultApps = [
        { name: 'DuckDuckGo', icon: 'ph-globe',           url: 'https://duckduckgo.com' },
        { name: 'Wikipedia',  icon: 'ph-book-open',        url: 'https://en.m.wikipedia.org' },
        { name: 'VS Code',    icon: 'ph-code',             url: 'https://vscode.dev' },
        { name: 'Music',      icon: 'ph-music-notes',      url: 'https://soundcloud.com' },
        { name: 'Gaming',     icon: 'ph-game-controller',  url: 'https://poki.com' },
        { name: 'Reddit',     icon: 'ph-reddit-logo',      url: 'https://reddit.com' }
      ];

      // ── INIT ─────────────────────────────────────────────────────────────────

      window.onload = function() {
        renderApps();
        renderBookmarks();
        updateClock();
        setInterval(updateClock, 1000);
        loadSession();
        document.getElementById('wallpaper-incognito').pause();
        initProxy();
      };

      // ── CLOCK ────────────────────────────────────────────────────────────────

      function updateClock() {
        var now = new Date();
        document.getElementById('clock-time').textContent =
          now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        document.getElementById('clock-date').textContent =
          now.toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' });
      }

      // ── SESSION ──────────────────────────────────────────────────────────────

      function saveSession() {
        if (isIncognito) { return; }
        localStorage.setItem('cineweb_tabs', JSON.stringify(normalTabs));
        localStorage.setItem('cineweb_active_id', activeTabId);
      }

      function loadSession() {
        var saved   = JSON.parse(localStorage.getItem('cineweb_tabs') || '[]');
        var savedId = localStorage.getItem('cineweb_active_id');
        if (saved.length === 0) { return; }
        normalTabs = saved;
        saved.forEach(function(t) {
          var n = parseInt(t.id.replace('tab-', ''), 10);
          if (n > tabCounter) { tabCounter = n; }
          addTabToStrip(t.id, t.title || new URL(t.url).hostname);
          createIframe(t.id, t.url);
        });
        var target = savedId && normalTabs.some(function(t) { return t.id === savedId; })
          ? savedId
          : normalTabs[normalTabs.length - 1].id;
        switchTab(target);
        updateResumeButton();
      }

      function updateResumeButton() {
        var btn  = document.getElementById('resume-btn');
        var tabs = isIncognito ? incognitoTabs : normalTabs;
        if (tabs.length > 0) {
          btn.classList.add('visible');
          btn.querySelector('span').textContent = isIncognito ? 'Return to Incognito' : 'Return to Session';
        } else {
          btn.classList.remove('visible');
        }
      }

      // ── TABS ─────────────────────────────────────────────────────────────────

      function createNewTab(url) {
        url = url || 'https://duckduckgo.com';
        tabCounter++;
        var id   = 'tab-' + tabCounter;
        var tabs = isIncognito ? incognitoTabs : normalTabs;
        tabs.push({ id: id, url: url, title: 'Loading...' });
        addTabToStrip(id, 'New Tab');
        createIframe(id, url);
        switchTab(id);
        if (!isIncognito) { saveSession(); }
      }

      function addTabToStrip(id, title) {
        var tab = document.createElement('div');
        tab.className = 'tab';
        tab.id = 'tab-ui-' + id;
        tab.innerHTML = '<i class="ph ph-globe-simple"></i>'
          + '<span class="tab-text">' + title + '</span>'
          + '<i class="ph ph-x tab-close"></i>';
        tab.addEventListener('click', function(e) {
          if (e.target.classList.contains('tab-close')) { closeTab(id, e); }
          else { switchTab(id); }
        });
        document.getElementById('tabs-strip').appendChild(tab);
        tab.scrollIntoView({ behavior: 'smooth' });
      }

      function createIframe(id, url) {
        var frame = document.createElement('iframe');
        frame.id  = 'frame-' + id;
        frame.src = toProxiedUrl(url);
        frame.setAttribute('sandbox', 'allow-scripts allow-same-origin allow-forms allow-popups allow-modals allow-pointer-lock');
        frame.setAttribute('allow', 'pointer-lock; fullscreen; autoplay');
        frame.onload = function() {
          try {
            var domain = new URL(url).hostname.replace('www.', '');
            var tabUi  = document.getElementById('tab-ui-' + id);
            if (tabUi) { tabUi.querySelector('.tab-text').innerText = domain; }
            var tabs = isIncognito ? incognitoTabs : normalTabs;
            var tab  = tabs.find(function(t) { return t.id === id; });
            if (tab) { tab.title = domain; if (!isIncognito) { saveSession(); } }
          } catch (e) {}
        };
        document.getElementById('content-area').appendChild(frame);
      }

      function switchTab(id) {
        activeTabId = id;
        var tabs    = isIncognito ? incognitoTabs : normalTabs;
        var tabData = tabs.find(function(t) { return t.id === id; });
        document.querySelectorAll('.tab').forEach(function(t) { t.classList.remove('active'); });
        var activeUi = document.getElementById('tab-ui-' + id);
        if (activeUi) { activeUi.classList.add('active'); }
        document.querySelectorAll('iframe').forEach(function(f) { f.classList.remove('active'); });
        var activeFrame = document.getElementById('frame-' + id);
        if (activeFrame) { activeFrame.classList.add('active'); }
        if (tabData) {
          document.getElementById('address-input').value = tabData.url;
          checkBookmarkStatus(tabData.url);
        }
        if (!isIncognito) { saveSession(); }
      }

      function closeTab(id, e) {
        e.stopPropagation();
        var tabs = isIncognito ? incognitoTabs : normalTabs;
        var idx  = tabs.findIndex(function(t) { return t.id === id; });
        if (idx > -1) {
          tabs.splice(idx, 1);
          var ui = document.getElementById('tab-ui-' + id);
          if (ui) { ui.remove(); }
          var fr = document.getElementById('frame-' + id);
          if (fr) { fr.remove(); }
          if (tabs.length === 0) { goHome(); }
          else { switchTab(tabs[Math.min(idx, tabs.length - 1)].id); }
        }
        if (!isIncognito) { saveSession(); }
      }

      function closeAllTabs() {
        var tabs = isIncognito ? incognitoTabs : normalTabs;
        tabs.length = 0;
        document.getElementById('tabs-strip').innerHTML = '';
        document.getElementById('content-area').innerHTML = '';
        showToast('Session cleared');
        goHome();
        if (!isIncognito) { saveSession(); }
      }

      // ── NAVIGATION ───────────────────────────────────────────────────────────

      function openBrowser(url) {
        document.body.classList.add('browser-active');
        createNewTab(url);
      }

      function resumeSession() { document.body.classList.add('browser-active'); }

      function goHome() {
        document.body.classList.remove('browser-active');
        updateResumeButton();
      }

      function navBack() {
        var f = document.getElementById('frame-' + activeTabId);
        if (f) { try { f.contentWindow.history.back(); } catch (e) {} }
      }

      function navForward() {
        var f = document.getElementById('frame-' + activeTabId);
        if (f) { try { f.contentWindow.history.forward(); } catch (e) {} }
      }

      function reloadTab() {
        var tabs = isIncognito ? incognitoTabs : normalTabs;
        var tab  = tabs.find(function(t) { return t.id === activeTabId; });
        var f    = document.getElementById('frame-' + activeTabId);
        if (f && tab) { f.src = toProxiedUrl(tab.url); showToast('Reloading...'); }
      }

      function toggleIncognito() {
        document.getElementById('tabs-strip').innerHTML = '';
        document.getElementById('content-area').innerHTML = '';
        isIncognito = !isIncognito;
        document.body.classList.toggle('incognito-mode');
        var vd = document.getElementById('wallpaper-default');
        var vi = document.getElementById('wallpaper-incognito');
        if (isIncognito) { vd.pause(); vi.play(); showToast('Incognito mode active'); }
        else { vi.pause(); vd.play(); showToast('Standard mode active'); }
        document.getElementById('incognito-toggle').style.color =
          isIncognito ? 'var(--accent-primary)' : 'inherit';
        var target = isIncognito ? incognitoTabs : normalTabs;
        if (target.length > 0) {
          target.forEach(function(t) { addTabToStrip(t.id, t.title || 'Loaded'); createIframe(t.id, t.url); });
          switchTab(target[target.length - 1].id);
        } else { createNewTab(); }
      }

      // ── SEARCH ───────────────────────────────────────────────────────────────

      function resolveUrl(raw) {
        raw = (raw || '').trim();
        if (!raw) { return null; }
        if (raw.startsWith('http://') || raw.startsWith('https://')) { return raw; }
        if (/^[a-zA-Z0-9-]+\.[a-zA-Z]{2,}/.test(raw)) { return 'https://' + raw; }
        return 'https://duckduckgo.com/?q=' + encodeURIComponent(raw);
      }

      function handleSearch(val) {
        var url = resolveUrl(val);
        if (!url) { return; }
        if (document.body.classList.contains('browser-active')) {
          var tabs = isIncognito ? incognitoTabs : normalTabs;
          var tab  = tabs.find(function(t) { return t.id === activeTabId; });
          if (tab) {
            tab.url = url;
            var f = document.getElementById('frame-' + activeTabId);
            if (f) { f.src = toProxiedUrl(url); }
            document.getElementById('address-input').value = url;
            var tabUi = document.getElementById('tab-ui-' + activeTabId);
            if (tabUi) { tabUi.querySelector('.tab-text').innerText = 'Loading...'; }
            if (!isIncognito) { saveSession(); }
          }
        } else { openBrowser(url); }
      }

      document.getElementById('home-search').addEventListener('keypress', function(e) {
        if (e.key === 'Enter') { handleSearch(e.target.value); e.target.value = ''; }
      });

      document.getElementById('address-input').addEventListener('keypress', function(e) {
        if (e.key === 'Enter') { handleSearch(e.target.value); e.target.blur(); }
      });

      document.getElementById('address-input').addEventListener('focus', function() { this.select(); });

      // ── BOOKMARKS ────────────────────────────────────────────────────────────

      function toggleBookmark() {
        var tabs = isIncognito ? incognitoTabs : normalTabs;
        var tab  = tabs.find(function(t) { return t.id === activeTabId; });
        if (!tab) { return; }
        var idx  = bookmarks.findIndex(function(b) { return b.url === tab.url; });
        var icon = document.getElementById('bookmark-icon');
        if (idx > -1) {
          bookmarks.splice(idx, 1);
          icon.className = 'ph ph-star';
          icon.style.color = 'inherit';
          showToast('Bookmark removed');
        } else {
          var name = prompt('Bookmark name:', new URL(tab.url).hostname.replace('www.', ''));
          if (name) {
            bookmarks.push({ title: name, url: tab.url });
            icon.className = 'ph ph-star-fill';
            icon.style.color = 'var(--accent-primary)';
            showToast('Bookmark added');
          }
        }
        localStorage.setItem('cineweb_bookmarks', JSON.stringify(bookmarks));
        renderBookmarks();
      }

      function checkBookmarkStatus(url) {
        var icon  = document.getElementById('bookmark-icon');
        var saved = bookmarks.some(function(b) { return b.url === url; });
        icon.className   = saved ? 'ph ph-star-fill' : 'ph ph-star';
        icon.style.color = saved ? 'var(--accent-primary)' : 'inherit';
      }

      function renderBookmarks() {
        var section = document.getElementById('bookmarks-section');
        var title   = section.querySelector('.section-title');
        section.innerHTML = '';
        section.appendChild(title);
        if (bookmarks.length === 0) { section.style.display = 'none'; return; }
        section.style.display = 'flex';
        bookmarks.forEach(function(bm) {
          var el = document.createElement('div');
          el.className = 'app-shortcut';
          el.style.transform = 'scale(0.85)';
          el.innerHTML = '<div class="app-icon-box" style="border-radius:50%;width:50px;height:50px;font-size:24px;">'
            + '<i class="ph ph-star-fill"></i></div>'
            + '<div class="app-label">' + bm.title + '</div>';
          el.onclick = function() { openBrowser(bm.url); };
          el.oncontextmenu = function(e) {
            e.preventDefault();
            if (confirm('Delete bookmark "' + bm.title + '"?')) {
              bookmarks = bookmarks.filter(function(b) { return b.url !== bm.url; });
              localStorage.setItem('cineweb_bookmarks', JSON.stringify(bookmarks));
              renderBookmarks();
            }
          };
          section.appendChild(el);
        });
      }

      function renderApps() {
        var grid = document.getElementById('app-grid');
        defaultApps.forEach(function(app) {
          var el = document.createElement('div');
          el.className = 'app-shortcut';
          el.innerHTML = '<div class="app-icon-box"><i class="ph ' + app.icon + '"></i></div>'
            + '<div class="app-label">' + app.name + '</div>';
          el.onclick = function() { openBrowser(app.url); };
          grid.appendChild(el);
        });
      }

      // ── MENU / TOAST ─────────────────────────────────────────────────────────

      function toggleMenu(e) {
        e.stopPropagation();
        document.getElementById('settings-menu').classList.toggle('open');
      }

      function closeMenu() {
        document.getElementById('settings-menu').classList.remove('open');
      }

      document.addEventListener('click', function(e) {
        var menu = document.getElementById('settings-menu');
        var btn  = document.getElementById('menu-btn');
        if (!menu.contains(e.target) && !btn.contains(e.target)) { menu.classList.remove('open'); }
      });

      function showToast(msg) {
        var c = document.getElementById('toast-container');
        var t = document.createElement('div');
        t.className = 'toast';
        t.innerText = msg;
        c.appendChild(t);
        setTimeout(function() {
          t.style.opacity   = '0';
          t.style.transform = 'translateY(10px)';
          setTimeout(function() { t.remove(); }, 300);
        }, 2500);
      }

